let raw = $json.candidates?.[0]?.content?.parts?.[0]?.text ?? "{}";

// Remove markdown code fences if model returns ```json ... ```
raw = raw.replace(/^```json\s*/i, "").replace(/^```\s*/i, "").replace(/\s*```$/i, "").trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch {
  parsed = {
    sentiment: "neutral",
    category: "other",
    priority: "medium",
    confidence: 0,
    draft_response: "Thank you for contacting SupportIQ. Our team will follow up shortly."
  };
}

const validPriorities = new Set(["low", "medium", "high"]);
const priority = typeof parsed.priority === "string" ? parsed.priority.toLowerCase() : "medium";

return [
  {
    json: {
      sentiment: parsed.sentiment ?? "neutral",
      category: parsed.category ?? "other",
      priority: validPriorities.has(priority) ? priority : "medium",
      confidence: Number(parsed.confidence ?? 0),
      draft_response: parsed.draft_response ?? "",
      raw_model_output: raw
    }
  }
];
